function p(n){const t=n.trim().split(/\r?\n/),r=t.findIndex(a=>{const s=c(a).map(i=>i.trim());return s.includes("ApplicationName")&&s.includes("StartDate")});if(r<0)throw new Error("CSV header row was not found. Expected ApplicationName and StartDate columns.");const e=c(t[r]).map(a=>a.trim());return t.slice(r+1).filter(Boolean).map(a=>{const s=c(a);return e.reduce((i,d,m)=>(i[d]=s[m]?.trim()??"",i),{})})}function f(n){return n.map((t,r)=>{const e=l(t.StartDate),a=l(t.StopDate)||e,s=u(t.isProd),i=u(t.isVDI);return{id:`${t.ApplicationName||"row"}-${r}`,source:t,applicationName:o(t.ApplicationName),functionality:o(t.Functionality),cadTool:o(t.cadTool),productLine:o(t.ProductLine),status:o(t.Status),region:o(t.Region),startDate:e,stopDate:a,date:e,month:e.slice(0,7),isProd:s,isVDI:i,environment:s?"Production":"Non-production",accessMode:i?"VDI":"Local",usageCount:1,uniqueUsers:0,timestamp:e?new Date(`${e}T00:00:00`).getTime():0,durationDays:g(e,a)}}).filter(t=>t.date&&Number.isFinite(t.timestamp))}function c(n){const t=[];let r="",e=!1;for(let a=0;a<n.length;a+=1){const s=n[a],i=n[a+1];s==='"'&&e&&i==='"'?(r+='"',a+=1):s==='"'?e=!e:s===","&&!e?(t.push(r),r=""):r+=s}return t.push(r),t}function o(n){return String(n||"").trim()||"Not Available"}function u(n){return String(n||"").trim().toLowerCase()==="true"}function l(n){const t=String(n||"").trim(),r=t.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);if(r){const[,a,s,i]=r;return`${i}-${a.padStart(2,"0")}-${s.padStart(2,"0")}`}const e=new Date(t);return Number.isNaN(e.getTime())?"":e.toISOString().slice(0,10)}function g(n,t){if(!n||!t)return 1;const r=new Date(`${n}T00:00:00`).getTime(),e=new Date(`${t}T00:00:00`).getTime(),a=Math.round((e-r)/864e5)+1;return Math.max(a,1)}self.onmessage=n=>{try{const t=f(p(n.data));self.postMessage({rows:t})}catch(t){self.postMessage({error:t.message||"Unable to parse CSV data."})}};
